-- a2e00000-0000-4000-8000-000000000000 動画別3問クイズ + 既存コース末(a2e90000-0000-4000-8000-000000000000)を末尾へ  自動生成
UPDATE public.lessons SET sort_order=1 WHERE id='a2e10000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='a2e20000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='a2e30000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='a2e40000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=99 WHERE id='a2e90000-0000-4000-8000-000000000000';

ON CONFLICT (id) DO UPDATE SET course_id=EXCLUDED.course_id,title=EXCLUDED.title,content_type=EXCLUDED.content_type,estimated_minutes=EXCLUDED.estimated_minutes,sort_order=EXCLUDED.sort_order;

DELETE FROM public.quiz_questions WHERE lesson_id IN ('a2e10900-0000-4000-8000-000000000000','a2e20900-0000-4000-8000-000000000000','a2e30900-0000-4000-8000-000000000000','a2e40900-0000-4000-8000-000000000000');

